mapper.select:


    and lname like concat('%', #{lname}, '%')
    and company like concat('%', #{company}, '%')
    and date_format(theday, '%Y-%m-%d') = #{theday}
    and theday >= #{beginTime}
    and theday <= #{endTime}

order by theday desc, id desc

select min(id) as id, lname, company, date_format(theday, '%Y-%m') as theday, sum(cast(ifnull(bigc, 0) as decimal(18,2))) as bigc, sum(cast(ifnull(bigck, 0) as decimal(18,2))) as bigck, sum(cast(ifnull(bigf, 0) as decimal(18,2))) as bigf, sum(cast(ifnull(smailc, 0) as decimal(18,2))) as smailc, sum(cast(ifnull(smailck, 0) as decimal(18,2))) as smailck, sum(cast(ifnull(smailf, 0) as decimal(18,2))) as smailf, sum(cast(ifnull(bigc_kuang, 0) as decimal(18,2))) as bigc_kuang, sum(cast(ifnull(bigc_fei, 0) as decimal(18,2))) as bigc_fei, sum(cast(ifnull(bigck_kuang, 0) as decimal(18,2))) as bigck_kuang, sum(cast(ifnull(bigck_fei, 0) as decimal(18,2))) as bigck_fei, sum(cast(ifnull(bigf_kuang, 0) as decimal(18,2))) as bigf_kuang, sum(cast(ifnull(bigf_fei, 0) as decimal(18,2))) as bigf_fei, sum(cast(ifnull(smailc_kuang, 0) as decimal(18,2))) as smailc_kuang, sum(cast(ifnull(smailc_fei, 0) as decimal(18,2))) as smailc_fei, sum(cast(ifnull(smailck_kuang, 0) as decimal(18,2))) as smailck_kuang, sum(cast(ifnull(smailck_fei, 0) as decimal(18,2))) as smailck_fei, sum(cast(ifnull(smailf_kuang, 0) as decimal(18,2))) as smailf_kuang, sum(cast(ifnull(smailf_fei, 0) as decimal(18,2))) as smailf_fei from a_mdispatch
and lname like concat('%', #{lname}, '%') and company like concat('%', #{company}, '%') and date_format(theday, '%Y-%m') = #{theday} and theday >= #{beginTime} and theday <= #{endTime}
group by date_format(theday, '%Y-%m'), lname, company order by date_format(theday, '%Y-%m') desc, lname asc

select date_format(create_time, '%Y-%m-%d') as stat_date, status, state, count(1) as event_count
from a_alert

    ifnull(is_deleted, '0') = '0'
    and status = #{status}
    and state = #{state}
    and create_time >= #{beginTime}
    and create_time <= #{endTime}

group by date_format(create_time, '%Y-%m-%d'), status, state
order by stat_date desc, event_count desc
